const END_PATTERNS = [
  /MONTANT\s*[AÀ]\s*PAYER/i,
  /MONTANT\s*[AÀ]\s*RETOURNER/i,
  /NET\s+A\s+PAYER/i,
  /TOTAL\s+TTC/i,
];
const NUMBER_PATTERNS = [
  /COMPTEURS\s+\d+\s*\/\s*(\d{4,6})/i,
  /FACTURE\s+N[°o]\s*[:\-]?\s*([A-Z0-9\-\/]{3,20})/i,
  /N[°o]\s*[:\-]?\s*0*(\d{3,6})\b/i,
];
const CHEQUE_KEYWORDS = [
  "PAYEZ CONTRE CE CHEQUE","PAYEZ CONTRE CE CHÈQUE",
  "A L'ORDRE DE","CORIS BANK","CHEQUE N°","CHÈQUE N°",
  "RECU CE JOUR","REÇU CE JOUR","SERIE A CHEQUE","B.P.F. CFA"
];

function isEndPage(text) { return END_PATTERNS.some(p => p.test(text)); }
function isCheque(text) {
  const upper = text.toUpperCase();
  return CHEQUE_KEYWORDS.filter(kw => upper.includes(kw)).length >= 2;
}
function extractInvoiceNo(text) {
  for (const p of NUMBER_PATTERNS) { const m = text.match(p); if (m) return m[1].trim(); }
  return null;
}

const mistralPages = $input.first().json.pages;
if (!Array.isArray(mistralPages)) throw new Error('json.pages[] introuvable');

const sorted = [...mistralPages].sort((a,b) => (a.index ?? 0) - (b.index ?? 0));
const pages = sorted.map((page, idx) => {
  const text = page.markdown || page.text || '';
  return { idx, text, isEnd: isEndPage(text), isCheque: isCheque(text), invNo: extractInvoiceNo(text) };
});

const groups = [];
let current = { pages: [], texts: [], invoiceNo: null };

for (const page of pages) {
  if (page.isCheque) { console.log('⛔ Chèque ignoré page', page.idx+1); continue; }
  current.pages.push(page.idx);
  current.texts.push(page.text);
  if (page.invNo && !current.invoiceNo) current.invoiceNo = page.invNo;
  if (page.isEnd) {
    groups.push({...current});
    current = { pages: [], texts: [], invoiceNo: null };
  }
}
if (current.pages.length > 0) groups.push({...current});

return groups.map((g, idx) => ({
  json: {
    pageText: g.texts.join('\n\n---\n\n'),
    pageIndex: idx + 1,
    invoiceNo: g.invoiceNo || `facture_${idx+1}`,
    isMultiPage: g.pages.length > 1,
    pageCount: g.pages.length,
    totalInvoices: groups.length,
  }
}));

