  ].filter(kw => text.includes(kw)).length;

  // Indicateurs ACHAT/CHARGE
  const achatScore = [
    'FOURNISSEUR', 'CODE MECEF', 'VENDEUR', 'ACHAT',
    'BON DE LIVRAISON', 'PROFORMA', 'CHARGE'
  ].filter(kw => text.includes(kw)).length;

