const items = $input.all();
const ecritures = [];

const parseAmt = (v) => {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Math.round(v);
  return Math.round(parseFloat(
    String(v).replace(/[Ff][Cc][Ff][Aa]/g,'').replace(/\s*\(\s*\d+\s*%\s*\)/g,'').replace(/\s/g,'').replace(/,/g,'')
  ) || 0);
};

for (const item of items) {
  let raw = item.json.output || item.json.text || item.json.message || '';
  if (typeof raw === 'object') raw = JSON.stringify(raw);

  let cleaned = raw.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();

  const match = cleaned.match(/\[[\s\S]*\]/);
  if (!match) {
    ecritures.push({ json: {
      'Date': '', 'Numéro de compte': 'ERREUR_PARSE',
      'Libellé de compte': 'Réponse agent non parseable',
      'Nom client': '', 'Pièce référence': '', 'Désignation': '',
      'Débit': 0, 'Crédit': 0, 'Montant Facture': 0,
      'Devise': 'FCFA', 'Nature opération': '', 'IFU': '', 'Code MECEF': ''
    }});
    continue;
  }

  let lignes = [];
  try { lignes = JSON.parse(match[0]); }
  catch(e) {
    ecritures.push({ json: {
      'Date': '', 'Numéro de compte': 'ERREUR_JSON',
      'Libellé de compte': 'Parse JSON échoué',
      'Nom client': '', 'Pièce référence': '', 'Désignation': '',
      'Débit': 0, 'Crédit': 0, 'Montant Facture': 0,
      'Devise': 'FCFA', 'Nature opération': '', 'IFU': '', 'Code MECEF': ''
    }});
    continue;
  }

  let fb = {};
  try { fb = item.json || {}; } catch(e) {}

  for (const l of lignes) {
    const debit  = parseAmt(l['Débit']  || l['debit']  || 0);
    const credit = parseAmt(l['Crédit'] || l['credit'] || 0);
    const ttc    = parseAmt(l['Montant Facture'] || fb.MONTANT_TTC || 0);

    ecritures.push({ json: {
      'Date':             l['Date']              || fb.DATE        || '',
      'Numéro de compte': String(l['Numéro de compte'] || l['numero_compte'] || ''),
      'Libellé de compte':l['Libellé de compte'] || l['libelle']  || '',
      'Nom client':       l['Nom client']        || fb.NOM_CLIENT || '',
      'Pièce référence':  l['Pièce référence']   || fb.NUM_FACTURE|| '',
      'Désignation':      l['Désignation']        || l['designation'] || '',
      'Débit':            debit,
      'Crédit':           credit,
      'Montant Facture':  ttc,
      'Devise':           'FCFA',
      'Nature opération': l['Nature opération']  || fb.TYPE_DOCUMENT || '',
      'IFU':              l['IFU']               || fb.IFU         || '',
      'Code MECEF':       l['Code MECEF']        || fb.CODE_MECEF  || ''
    }});
  }
}
return ecritures;

for (const item of items) {
  const prevData = $("Pré-classification par mots-clés").item.json;
  item.json = { ...prevData, ...item.json };
}
return items;

for (const item of items) {
  let output = item.json.output;
  if (typeof output === 'string') {
    try {
      const cleaned = output.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();
      const parsed = JSON.parse(cleaned);
      output = Array.isArray(parsed) ? parsed[0] : parsed;
    } catch(e) {
      output = {};
    }
  }
  if (Array.isArray(output)) output = output[0] || {};
  item.json.output = output;
}
return items;
